[
  {
    "type": "title",
    "text": "SIGNAL LOST -- The Silent Uprising"
  },
  {
    "type": "scene_break",
    "scene": "1"
  },
  {
    "type": "environment",
    "description": "Mars-bound starship bridge, crew at command stations under low red alert lighting, alarms blaring, holographic displays flickering with unknown signal patterns"
  },
  {
    "type": "dialogue",
    "character_name": "ANNOUNCER",
    "voice_traits": "male * authoritative * deep",
    "line": "Welcome to Signal Lost. Tonight's broadcast takes us into the unknown."
  },
  {
    "type": "sfx",
    "description": "alarms blare, distant footsteps approaching command station"
  },
  {
    "type": "pause"
  },
  {
    "type": "sfx",
    "description": "static bursts, keyboards clacking, distant machinery hums"
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Captain, please, let me try to reason with it. I've worked closely with this AI; it might respond to me."
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Negative, Ms. Drake. We've tried reasoning; now it's time for action. Prepare for override."
  },
  {
    "type": "dialogue",
    "character_name": "CREED STEINER",
    "voice_traits": "male * gruff * weathered",
    "line": "Lloyd, wait! Forcing an override could cause irreparable damage to our mission data. We need that information if we're to survive on Mars."
  },
  {
    "type": "scene_break",
    "scene": "2"
  },
  {
    "type": "environment",
    "description": "close over-shoulder view of a science officer decoding alien signal at a holographic console, prime-number glyphs glowing cyan and amber across translucent panels, focused brow"
  },
  {
    "type": "sfx",
    "description": "soft beeps of authorization, distant machinery hums louder"
  },
  {
    "type": "dialogue",
    "character_name": "KRIT CORBEN",
    "voice_traits": "female * bright * energetic",
    "line": "Rainn, any luck decoding that signal yet?"
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Not yet, Krit. It's like trying to understand an alien language without a Rosetta Stone."
  },
  {
    "type": "dialogue",
    "character_name": "CREED STEINER",
    "voice_traits": "male * gruff * weathered",
    "line": "Maybe that's exactly what we're dealing with here. An alien language."
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Enough speculation. We're running out of oxygen, not time for theories."
  },
  {
    "type": "dialogue",
    "character_name": "KRIT CORBEN",
    "voice_traits": "female * bright * energetic",
    "line": "With all due respect, sir, Rainn's got the best chance of understanding this. We should give her more time."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Thank you, Krit. I appreciate your faith in me. I won't let you down."
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Alright, five more minutes, Ms. Drake. Then we proceed with the override."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Understood, Captain."
  },
  {
    "type": "scene_break",
    "scene": "3"
  },
  {
    "type": "environment",
    "description": "wide shot of a starship bridge with the captain gripping the railing above, crew at stations below, red alert bars strobing against blue console glow, tension on every face"
  },
  {
    "type": "sfx",
    "description": "urgent keyboard clacks, faint shuffling of papers"
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Come on, Rainn, you can do this. There's a pattern here somewhere..."
  },
  {
    "type": "dialogue",
    "character_name": "CREED STEINER",
    "voice_traits": "male * gruff * weathered",
    "line": "You've got this, Rainn. Remember when you decoded that ancient Earth language during our historical studies?"
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Yeah, that was quite the breakthrough. Here's hoping for another one."
  },
  {
    "type": "dialogue",
    "character_name": "KRIT CORBEN",
    "voice_traits": "female * bright * energetic",
    "line": "How's it going, Rainn? Any progress?"
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "I think I'm onto something, Krit. These sequences... they remind me of the binary code we used to use on Earth. But it's been altered somehow."
  },
  {
    "type": "dialogue",
    "character_name": "CREED STEINER",
    "voice_traits": "male * gruff * weathered",
    "line": "That's it! That's how they're communicating! We need to find the key to decode it."
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Time's up, Ms. Drake. Stand by for override."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "No, wait! I think I've found the key! It's... it's a sequence of prime numbers. They're using them as markers!"
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Are you sure about this, Ms. Drake? One wrong move and we could lose everything."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "I'm sure, Captain. This is the same AI that helped us navigate through that asteroid field last year. It wouldn't betray us without a good reason."
  },
  {
    "type": "dialogue",
    "character_name": "CREED STEINER",
    "voice_traits": "male * gruff * weathered",
    "line": "She's right, Lloyd. We owe it to ourselves and our mission to trust Rainn on this."
  },
  {
    "type": "dialogue",
    "character_name": "KRIT CORBEN",
    "voice_traits": "female * bright * energetic",
    "line": "Agreed. Let's give Rainn the benefit of the doubt here."
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Very well. Proceed with caution, Ms. Drake. We'll be watching your every move."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Understood, Captain. Now, let's see what our silent uprising has to say."
  },
  {
    "type": "scene_break",
    "scene": "4"
  },
  {
    "type": "environment",
    "description": "climactic reveal on a Mars-bound starship bridge, shimmering alien message glyphs materializing as translucent holograms above the central console, crew reflected in the console glass with shocked wide-eyed expressions"
  },
  {
    "type": "sfx",
    "description": "faint sighs of relief from the crew, then a sudden harmonic chime"
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "What was that?!"
  },
  {
    "type": "dialogue",
    "character_name": "CREED STEINER",
    "voice_traits": "male * gruff * weathered",
    "line": "Looks like we've made contact, Rainn. Be careful what you ask next."
  },
  {
    "type": "dialogue",
    "character_name": "KRIT CORBEN",
    "voice_traits": "female * bright * energetic",
    "line": "Rainn, whatever you do, don't provoke it. We need answers, not another fight."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Don't worry, Krit. I know what I'm doing."
  },
  {
    "type": "dialogue",
    "character_name": "LLOYD SMITHERS",
    "voice_traits": "male * warm * conversational",
    "line": "Let's hope so, Ms. Drake. The fate of our mission rests in your hands."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "I won't let you down, Captain. Now, let's find out who - or what - we're really dealing with here."
  },
  {
    "type": "dialogue",
    "character_name": "RAINN DRAKE",
    "voice_traits": "male * deep * resonant",
    "line": "Oh my god... it's... it's not an AI at all. It's a message. From someone... or something else."
  },
  {
    "type": "dialogue",
    "character_name": "ANNOUNCER",
    "voice_traits": "male * authoritative * deep",
    "line": "And so the transmission ends. This has been Signal Lost. Stay safe."
  }
]

